type AskLocalOptions = Parameters<typeof askLocal>[1];
type AskLocalMode = NonNullable<AskLocalOptions>["mode"];
type AskLocalResult = Awaited<ReturnType<typeof askLocal>>;

type AskLocalWithFallbackResult = {
  response: AskLocalResult;
  downgradedFromMode?: AskLocalMode;
  bypassedMultilangGate?: boolean;
};

type RunAskOptions = {
  source?: "manual" | "voice_auto";
  bypassWorkstationDispatch?: boolean;
  forceReasoningDispatch?: boolean; requiresBackendAskEntrypoint?: boolean;
  suppressWorkstationPayloadActions?: boolean;
  answerContract?: HelixAskAnswerContract;
  routeMetadata?: HelixAskRouteMetadata;
  contextMode?: "attached" | "isolated";
  skipContextChooser?: boolean;
  visualCapability?: Record<string, unknown>;
  visualEvidence?: Record<string, unknown>;
  imageAttachment?: HelixAskImageAttachment;
  attachments?: HelixAskAttachment[];
  turnInputItems?: HelixTurnInputItem[];
  imageAttachmentLensRun?: ImageAttachmentLensRunV1 | null;
};

